mapper.insert:
INSERT INTO bluenote_notification.notification_unread_counter (
    user_id, category, unread_count, updated_at
) VALUES (
    #{userId}, #{category}, GREATEST(0, #{delta}), #{updatedAt}
)
ON DUPLICATE KEY UPDATE
    unread_count = GREATEST(0, unread_count + VALUES(unread_count) - GREATEST(0, -#{delta})),
    updated_at = VALUES(updated_at)

INSERT INTO bluenote_notification.notification_unread_counter (
    user_id, category, unread_count, updated_at
) VALUES (
    #{userId}, #{category}, GREATEST(0, #{unreadCount}), #{updatedAt}
)
ON DUPLICATE KEY UPDATE
    unread_count = VALUES(unread_count),
    updated_at = VALUES(updated_at)

mapper.select:
SELECT user_id, category, unread_count, updated_at
FROM bluenote_notification.notification_unread_counter
WHERE user_id = #{userId}
